// Each palette is a flat RGB byte stream (256 × 3 = 768 bytes), stored
// base64 and decoded once at module load into a Uint8Array. The resolver
// in colormaps.ts turns these into the shader's colormap LUT texture;
// customer-supplied { stops } specs are resampled to the same 256 grid.

function decode(b64: string): Uint8Array {
  const bin = atob(b64);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}

